const crypto = require('node:crypto');
const secret = $env.N8N_INTEGRATION_SECRET;
if (!secret) throw new Error('N8N_INTEGRATION_SECRET is not configured');
return items.map(({ json }) => {
  const sourceUrl = json.link || json.url || json.sourceUrl;
  if (!sourceUrl) throw new Error('RSS item has no source URL');
  const canonicalUrl = String(sourceUrl).split('#')[0];
  const rawContent = String(json.content || json.contentSnippet || json.text || json.description || '').trim();
  const externalId = String(json.guid || json.id || canonicalUrl);
  const inferredLocale = /[а-яё]/i.test(String(json.title || '') + ' ' + rawContent) ? 'ru' : 'en';
  const enclosure = json.enclosure?.url || null;
  const imageUrl = json.imageUrl || enclosure || null;
  const payload = {
    externalId,
    sourcePlatform: 'rss',
    sourceName: json.feedTitle || json.sourceName || 'RSS',
    sourceUrl,
    canonicalUrl,
    author: json.creator || json.author || null,
    locale: json.locale === 'ru' || json.locale === 'en' ? json.locale : inferredLocale,
    title: String(json.title || 'Untitled').slice(0, 500),
    rawContent: rawContent || String(json.title || 'Untitled'),
    imageUrl,
    publishedAt: json.isoDate || json.pubDate || null,
    fingerprint: crypto.createHash('sha256').update(canonicalUrl + '|' + rawContent.replace(/\s+/g, ' ')).digest('hex'),
    category: json.category || 'ai'
  };
  const rawBody = JSON.stringify(payload);
  const signature = 'sha256=' + crypto.createHmac('sha256', secret).update(rawBody).digest('hex');
  return { json: { payload, rawBody, signature } };
});

if ($json.duplicate === true) return [];
const source = $('Normalize + Sign Ingest').item.json.payload;
if (!$json.article?.id || !$json.article?.version) throw new Error('Ingest response has no article');
return [{ json: { article: $json.article, source } }];

