const crypto = require('node:crypto');
const secret = $env.N8N_INTEGRATION_SECRET;
const prepared = $('Only New Articles').item.json;
const content = $json.choices?.[0]?.message?.content;
if (!content) throw new Error('AI response does not contain JSON content');
let editorial;
try { editorial = typeof content === 'string' ? JSON.parse(content) : content; }
catch (error) { throw new Error('AI returned invalid JSON: ' + error.message); }
const payload = {
  articleId: prepared.article.id,
  expectedVersion: prepared.article.version,
  locale: prepared.source.locale,
  title: String(editorial.title || '').slice(0, 220),
  summary: String(editorial.summary || '').slice(0, 800),
  body: String(editorial.body || ''),
  seoTitle: editorial.seoTitle ? String(editorial.seoTitle).slice(0, 220) : null,
  seoDescription: editorial.seoDescription ? String(editorial.seoDescription).slice(0, 500) : null,
  telegramText: editorial.telegramText ? String(editorial.telegramText).slice(0, 4096) : null,
  category: String(editorial.category || prepared.source.category || 'ai').slice(0, 80),
  tags: Array.isArray(editorial.tags) ? editorial.tags.slice(0, 12).map(String) : [],
  factWarnings: Array.isArray(editorial.factWarnings) ? editorial.factWarnings.slice(0, 20).map(String) : []
};
if (!payload.title || !payload.summary || !payload.body) throw new Error('AI editorial result is incomplete');
const rawBody = JSON.stringify(payload);
const signature = 'sha256=' + crypto.createHmac('sha256', secret).update(rawBody).digest('hex');
return [{ json: { payload, rawBody, signature } }];

